<script setup lang="ts">import { ref, onMounted } from 'vue'import { ElMessage } from 'element-plus'import { parseResponseJson } from '@/utils/parseApiResponse'interface UploadHistory {  file_id: string  filename: string  file_type: string  file_size: number  status: string  chunk_count: number  uploaded_at: string}interface ProcessStep {  name: string  status: 'pending' | 'processing' | 'completed' | 'error'  progress: number}const file = ref<File | null>(null)const loading = ref(false)const fileId = ref('')const taskId = ref('')const uploadHistory = ref<UploadHistory[]>([])const processSteps = ref<ProcessStep[]>([  { name: '鏂囦欢涓婁紶', status: 'pending', progress: 0 },  { name: '鎻愪氦瑙ｆ瀽', status: 'pending', progress: 0 },  { name: '鍐呭瑙ｆ瀽', status: 'pending', progress: 0 },  { name: '鍚戦噺鍖栧鐞?, status: 'pending', progress: 0 },  { name: '绱㈠紩鍏ュ簱', status: 'pending', progress: 0 }])// 杞瑙ｆ瀽杩涘害let pollTimer: ReturnType<typeof setTimeout> | null = nullconst stopPolling = () => {  if (pollTimer) {    clearTimeout(pollTimer)    pollTimer = null  }}const pollParseStatus = async (taskId: string) => {  try {    const res = await fetch(`/api/parse/status/${taskId}`)    const data = (await parseResponseJson(res)) as Record<string, any>    if (data.status === 'pending') {      processSteps.value[2].status = 'processing'    } else if (data.status === 'processing') {      // 10% 鈫?70% 瀵瑰簲 parsing 闃舵      processSteps.value[2].status = 'processing'      processSteps.value[2].progress = Math.min(70, Math.max(10, data.progress))      // 70% 鈫?90% 瀵瑰簲 indexing 闃舵      if (data.progress >= 70) {        processSteps.value[3].status = 'processing'        processSteps.value[3].progress = Math.min(90, data.progress)      }      if (data.progress >= 90) {        processSteps.value[4].status = 'processing'        processSteps.value[4].progress = data.progress      }    } else if (data.status === 'done') {      processSteps.value[2].status = 'completed'      processSteps.value[2].progress = 100      processSteps.value[3].status = 'completed'      processSteps.value[3].progress = 100      processSteps.value[4].status = 'completed'      processSteps.value[4].progress = 100      stopPolling()      await loadHistory()      ElMessage.success('瑙ｆ瀽瀹屾垚锛屾枃妗ｅ凡鍏ュ簱')      loading.value = false      return    } else if (data.status === 'failed') {      processSteps.value.forEach(s => { if (s.status === 'processing') s.status = 'error' })      stopPolling()      ElMessage.error('瑙ｆ瀽澶辫触: ' + (data.error || '鏈煡閿欒'))      loading.value = false      return    }    pollTimer = setTimeout(() => pollParseStatus(taskId), 2000)  } catch (e: any) {    stopPolling()    ElMessage.error('鏌ヨ瑙ｆ瀽鐘舵€佸け璐?)    loading.value = false  }}const handleUpload = async () => {  if (!file.value) {    ElMessage.warning('璇峰厛閫夋嫨鏂囦欢')    return  }  loading.value = true  fileId.value = ''  taskId.value = ''  stopPolling()  // 閲嶇疆姝ラ  processSteps.value.forEach(s => { s.status = 'pending'; s.progress = 0 })  try {    // 姝ラ1锛氫笂浼犳枃浠?    processSteps.value[0].status = 'processing'    const formData = new FormData()    formData.append('file', file.value)    const uploadRes = await fetch('/api/upload', { method: 'POST', body: formData })    const uploadData = (await parseResponseJson(uploadRes)) as Record<string, any>    if (!uploadRes.ok) throw new Error(uploadData.detail || '涓婁紶澶辫触')    fileId.value = uploadData.file_id    processSteps.value[0].status = 'completed'    processSteps.value[0].progress = 100    if (uploadData.duplicate) {      ElMessage.info('鏂囦欢宸插瓨鍦紝宸茶烦杩囬噸澶嶄笂浼?)    }    // 姝ラ2锛氭彁浜よВ鏋愪换鍔?    processSteps.value[1].status = 'processing'    const parseRes = await fetch('/api/parse', {      method: 'POST',      headers: { 'Content-Type': 'application/json' },      body: JSON.stringify({ file_id: fileId.value })    })    const parseData = (await parseResponseJson(parseRes)) as Record<string, any>    if (!parseRes.ok) throw new Error(parseData.detail || '鎻愪氦瑙ｆ瀽澶辫触')    taskId.value = parseData.task_id    processSteps.value[1].status = 'completed'    processSteps.value[1].progress = 100    // 寮€濮嬭疆璇?    pollTimer = setTimeout(() => pollParseStatus(taskId.value), 1500)  } catch (e: any) {    processSteps.value.forEach(s => { if (s.status === 'processing') s.status = 'error' })    ElMessage.error(e.message || '涓婁紶澶辫触')    loading.value = false  }}const loadHistory = async () => {  try {    const res = await fetch('/api/files')    const data = (await parseResponseJson(res)) as { files?: UploadHistory[] }    if (res.ok) uploadHistory.value = data.files || []  } catch {    // 闈欓粯澶辫触锛屼笉鎵撴壈涓绘祦绋?  }}const handleFileSelect = (e: Event) => {  const input = e.target as HTMLInputElement  file.value = input.files?.[0] || null}const getFileIcon = (filename: string) => {  if (filename.endsWith('.pdf')) return '馃摃'  if (filename.endsWith('.docx')) return '馃搫'  if (filename.endsWith('.xlsx')) return '馃搳'  if (filename.endsWith('.txt')) return '馃摑'  if (filename.endsWith('.md')) return '馃搵'  return '馃搧'}const getStatusIcon = (status: string) => {  if (status === 'indexed') return '鉁?  if (status === 'parsed') return '鈴?  if (status === 'uploaded') return '鈫?  if (status === 'failed') return '鉁?  return '鈥?}const getStatusColor = (status: string) => {  if (status === 'indexed') return 'bg-green/10 text-green'  if (status === 'parsed') return 'bg-accent/10 text-accent'  if (status === 'uploaded') return 'bg-blue-100 text-blue-600'  if (status === 'failed') return 'bg-red/10 text-red'  return 'bg-muted/10 text-muted'}const getStatusLabel = (status: string) => {  if (status === 'indexed') return '宸插叆搴?  if (status === 'parsed') return '宸茶В鏋?  if (status === 'uploaded') return '宸蹭笂浼?  if (status === 'failed') return '澶辫触'  return status}const formatSize = (bytes: number) => {  if (bytes < 1024) return bytes + ' B'  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB'  return (bytes / (1024 * 1024)).toFixed(1) + ' MB'}const formatTime = (iso: string) => {  try {    return new Date(iso).toLocaleString('zh-CN')  } catch {    return iso  }}const totalChunks = () => uploadHistory.value.reduce((sum, f) => sum + (f.chunk_count || 0), 0)const totalSize = () => uploadHistory.value.reduce((sum, f) => sum + (f.file_size || 0), 0)const deletingId = ref('')const handleDelete = async (record: UploadHistory) => {  if (!confirm(`纭畾鍒犻櫎鏂囦欢銆?{record.filename}銆嶏紵\n鍒犻櫎鍚庡皢鏃犳硶鎭㈠锛屼笖鍚戦噺绱㈠紩涔熶細涓€骞舵竻闄ゃ€俙)) return  deletingId.value = record.file_id  try {    const res = await fetch(`/api/files/${record.file_id}`, { method: 'DELETE' })    const data = (await parseResponseJson(res)) as Record<string, any>    if (!res.ok) throw new Error(data.detail || '鍒犻櫎澶辫触')    uploadHistory.value = uploadHistory.value.filter(r => r.file_id !== record.file_id)    ElMessage.success('鍒犻櫎鎴愬姛')  } catch (e: any) {    ElMessage.error(e.message || '鍒犻櫎澶辫触')  } finally {    deletingId.value = ''  }}const handleReParse = async (record: UploadHistory) => {  const confirmed = confirm(    `纭畾瑕佸銆?{record.filename}銆嶉噸鏂拌В鏋愶紵\n` +    `路 灏嗗垹闄ゆ棫鐨勫悜閲忕储寮昞n` +    `路 鐢?VLM 閲嶆柊瑙ｆ瀽锛堥渶 Ollama 杩愯锛塡n` +    `路 瀹屾垚鍚庤嚜鍔ㄦ竻闄よ鏂囦欢鐨勯棶绛旂紦瀛榒  )  if (!confirmed) return  try {    // 璋冪敤鏂扮殑 /files/{file_id}/reparse锛堜竴閿畬鎴愶細鍒犵储寮?+ 閲嶈В鏋?+ 娓呯紦瀛橈級    const res = await fetch(`/api/files/${record.file_id}/reparse`, { method: 'POST' })    const data = (await parseResponseJson(res)) as Record<string, any>    if (!res.ok) throw new Error(data.detail || '鎻愪氦澶辫触')    ElMessage.success(`閲嶆柊瑙ｆ瀽浠诲姟宸叉彁浜わ紝浠诲姟 ID锛?{data.task_id}锛?绉掑悗寮€濮嬭疆璇㈣繘搴?..`)    // 2.5s 鍚庡紑濮嬭疆璇㈣繘搴︼紙灞曠ず褰撳墠姝ラ鐘舵€侊級    setTimeout(() => pollReParseStatus(data.task_id), 2500)  } catch (e: any) {    ElMessage.error(e.message || '鎻愪氦澶辫触')  }}// 杞閲嶆柊瑙ｆ瀽浠诲姟鐨勮繘搴?const reparsePollTimer = ref<ReturnType<typeof setTimeout> | null>(null)const currentReParseTaskId = ref('')const stopReParsePoll = () => {  if (reparsePollTimer.value) {    clearTimeout(reparsePollTimer.value)    reparsePollTimer.value = null  }}const pollReParseStatus = async (taskId: string) => {  if (!taskId) return  currentReParseTaskId.value = taskId  try {    const res = await fetch(`/api/parse/status/${taskId}`)    const data = (await parseResponseJson(res)) as Record<string, any>    if (data.status === 'done') {      stopReParsePoll()      // 鑷姩娓呴櫎璇ユ枃浠剁殑闂瓟缂撳瓨      try {        await fetch(`/api/cache/clear/${data.file_id}`, { method: 'POST' })      } catch { /* ignore */ }      await loadHistory()      ElMessage.success('閲嶆柊瑙ｆ瀽瀹屾垚锛佽鏂囦欢鐨勯棶绛旂紦瀛樺凡娓呴櫎锛屽彲閲嶆柊娴嬭瘯銆?)    } else if (data.status === 'failed') {      stopReParsePoll()      ElMessage.error('閲嶆柊瑙ｆ瀽澶辫触: ' + (data.error || '鏈煡閿欒'))    } else {      // pending / processing锛氱户缁疆璇?      const msg = data.status === 'pending'        ? '鎺掗槦涓?..'        : data.status === 'processing'          ? `瑙ｆ瀽杩涘害 ${data.progress ?? 0}%`          : ''      ElMessage.info(msg)      reparsePollTimer.value = setTimeout(() => pollReParseStatus(taskId), 3000)    }  } catch {    stopReParsePoll()    ElMessage.error('鏌ヨ閲嶆柊瑙ｆ瀽鐘舵€佸け璐?)  }}const batchParsing = ref(false)const batchResult = ref<string>('')const handleBatchParse = async () => {  batchParsing.value = true  batchResult.value = ''  try {    const res = await fetch('/api/parse/batch', { method: 'POST' })    const data = (await parseResponseJson(res)) as Record<string, any>    if (!res.ok) throw new Error(data.detail || '鎵归噺瑙ｆ瀽澶辫触')    const submitted = data.tasks?.filter((t: any) => t.status === 'submitted').length || 0    batchResult.value = data.message || `宸叉彁浜?${submitted} 涓В鏋愪换鍔    ElMessage.success(batchResult.value)    // 姣?绉掑埛鏂颁竴娆″巻鍙茶褰曪紝鐩村埌娌℃湁 uploaded 鐘舵€?    let checks = 0    const interval = setInterval(async () => {      await loadHistory()      checks++      const stillPending = uploadHistory.value.some(f => f.status === 'uploaded')      if (!stillPending || checks > 30) clearInterval(interval)    }, 2000)  } catch (e: any) {    ElMessage.error(e.message || '鎵归噺瑙ｆ瀽澶辫触')  } finally {    batchParsing.value = false  }}</script><template>  <div class="space-y-6">    <div class="text-xs font-bold tracking-widest text-muted uppercase pb-2.5 border-b border-border-l">      鏂囨。涓婁紶涓庤В鏋愬叆搴?    </div>    <!-- 鏂囦欢缁熻 -->    <div class="grid grid-cols-3 gap-4">      <div class="bg-white border border-border rounded-lg p-4 text-center">        <div class="text-2xl font-bold text-accent">{{ uploadHistory.length }}</div>        <div class="text-xs text-muted mt-1">宸蹭笂浼犳枃妗?/div>      </div>      <div class="bg-white border border-border rounded-lg p-4 text-center">        <div class="text-2xl font-bold text-accent">{{ formatSize(totalSize()) }}</div>        <div class="text-xs text-muted mt-1">鎬诲ぇ灏?/div>      </div>      <div class="bg-white border border-border rounded-lg p-4 text-center">        <div class="text-2xl font-bold text-accent">{{ totalChunks() }}</div>        <div class="text-xs text-muted mt-1">鎬绘枃鏈潡</div>      </div>    </div>    <!-- 涓婁紶鍖哄煙 -->    <div class="grid grid-cols-12 gap-8">      <div class="col-span-5">        <label class="block text-sm font-medium text-text2 mb-2">閫夋嫨鏂囦欢</label>        <label class="bg-white border-2 border-dashed border-border rounded-lg p-12 text-center hover:border-accent transition-colors cursor-pointer h-full flex flex-col items-center justify-center block">          <div class="text-5xl mb-4">馃搧</div>          <div class="text-sm text-text2 mb-2 font-medium">鎷栨嫿鏂囦欢鑷虫锛屾垨鐐瑰嚮閫夋嫨</div>          <div class="text-xs text-muted mb-6">鏀寔 PDF 路 DOCX 路 XLSX 路 TXT 路 MD</div>          <div v-if="file" class="text-xs text-accent font-medium mb-4">            宸查€夋嫨锛歿{ file.name }}          </div>          <input            type="file"            class="hidden"            accept=".pdf,.docx,.xlsx,.txt,.md,.xls"            @change="handleFileSelect"          />        </label>      </div>      <div class="col-span-2"></div>      <div class="col-span-5 space-y-4">        <!-- 涓婁紶鎸夐挳 -->        <button          @click="handleUpload"          :disabled="loading || !file"          class="w-full px-4 py-3 bg-accent text-white font-medium rounded-md hover:bg-blue-600 disabled:opacity-50 transition-colors"        >          {{ loading ? '澶勭悊涓?..' : '涓婁紶骞惰В鏋? }}        </button>        <!-- File ID -->        <div v-if="fileId">          <label class="block text-sm font-medium text-text2 mb-1">File ID</label>          <div class="flex gap-2">            <input              :value="fileId"              readonly              type="text"              class="flex-1 px-3 py-2 bg-surface border border-border rounded-md text-sm text-text font-mono"            />            <button              @click="() => { navigator.clipboard.writeText(fileId); ElMessage.success('宸插鍒?) }"              class="px-3 py-2 bg-accent/10 text-accent text-sm font-medium rounded-md hover:bg-accent/20"            >              澶嶅埗            </button>          </div>        </div>      </div>    </div>    <!-- 澶勭悊姝ラ -->    <div v-if="loading" class="bg-white border border-border rounded-lg p-6">      <div class="text-sm font-bold text-text mb-4">澶勭悊姝ラ</div>      <div class="space-y-3">        <div v-for="(step, index) in processSteps" :key="index" class="flex items-center gap-3">          <div            class="w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0"            :class="{              'bg-green text-white': step.status === 'completed',              'bg-accent text-white': step.status === 'processing',              'bg-red text-white': step.status === 'error',              'bg-surface2 text-text2': step.status === 'pending'            }"          >            {{ step.status === 'completed' ? '鉁? : step.status === 'processing' ? '鈴? : index + 1 }}          </div>          <div class="flex-1">            <div class="text-sm text-text font-medium">{{ step.name }}</div>            <div v-if="step.status !== 'pending'" class="w-full bg-surface2 rounded-full h-1.5 mt-1 overflow-hidden">              <div                class="h-full bg-accent transition-all duration-300"                :style="{ width: step.progress + '%' }"              ></div>            </div>          </div>        </div>      </div>    </div>    <!-- 涓婁紶鍘嗗彶 -->    <div>      <div class="flex items-center justify-between pb-2.5 border-b border-border-l mb-4">        <div class="text-xs font-bold tracking-widest text-muted uppercase">          涓婁紶鍘嗗彶        </div>        <div class="flex items-center gap-3">          <button            @click="handleBatchParse"            :disabled="batchParsing || !uploadHistory.some(f => f.status === 'uploaded')"            class="text-xs px-3 py-1 bg-accent text-white rounded hover:bg-blue-600 disabled:opacity-40 font-medium transition-colors"          >            {{ batchParsing ? '瑙ｆ瀽涓?..' : '涓€閿В鏋愬叏閮? }}          </button>          <button            @click="loadHistory"            class="text-xs text-accent hover:text-blue-600"          >            鍒锋柊          </button>        </div>      </div>      <div class="bg-white border border-border rounded-lg overflow-hidden">        <table class="w-full text-sm">          <thead>            <tr class="bg-surface2 border-b border-border">              <th class="px-4 py-3 text-left font-semibold text-text2">鏂囦欢鍚?/th>              <th class="px-4 py-3 text-left font-semibold text-text2">澶у皬</th>              <th class="px-4 py-3 text-left font-semibold text-text2">鏂囨湰鍧?/th>              <th class="px-4 py-3 text-left font-semibold text-text2">鐘舵€?/th>              <th class="px-4 py-3 text-left font-semibold text-text2">File ID</th>              <th class="px-4 py-3 text-left font-semibold text-text2">鎿嶄綔</th>            </tr>          </thead>          <tbody>            <tr v-for="record in uploadHistory" :key="record.file_id" class="border-b border-border-l hover:bg-surface2">              <td class="px-4 py-3 text-text">                <div class="flex items-center gap-2">                  <span class="text-lg">{{ getFileIcon(record.filename) }}</span>                  <span>{{ record.filename }}</span>                </div>              </td>              <td class="px-4 py-3 text-text2">{{ formatSize(record.file_size) }}</td>              <td class="px-4 py-3 text-text2">{{ record.chunk_count || 0 }} 鍧?/td>              <td class="px-4 py-3">                <span                  class="px-2 py-1 rounded text-xs font-medium"                  :class="getStatusColor(record.status)"                >                  {{ getStatusIcon(record.status) }} {{ getStatusLabel(record.status) }}                </span>              </td>              <td class="px-4 py-3 text-text2 font-mono text-xs">                <div class="flex items-center gap-2">                  <span>{{ record.file_id.slice(0, 8) }}...</span>                  <button                    @click="() => { navigator.clipboard.writeText(record.file_id); ElMessage.success('宸插鍒?) }"                    class="text-accent hover:text-blue-600"                  >                    馃搵                  </button>                </div>              </td>              <td class="px-4 py-3">                <div class="flex items-center gap-1.5">                  <button                    v-if="record.status === 'uploaded' || record.status === 'indexed'"                    @click="handleReParse(record)"                    class="px-2 py-1 text-xs bg-blue-100 text-blue-600 rounded hover:bg-blue-200 font-medium"                  >                    閲嶆柊瑙ｆ瀽                  </button>                  <button                    @click="handleDelete(record)"                    :disabled="deletingId === record.file_id"                    class="px-2 py-1 text-xs bg-red/10 text-red rounded hover:bg-red/20 font-medium disabled:opacity-40"                  >                    {{ deletingId === record.file_id ? '鍒犻櫎涓? : '鍒犻櫎' }}                  </button>                </div>              </td>            </tr>            <tr v-if="uploadHistory.length === 0">              <td colspan="6" class="px-4 py-8 text-center text-muted">鏆傛棤涓婁紶璁板綍</td>            </tr>          </tbody>        </table>      </div>    </div>  </div></template><style scoped></style>